int max_1d_range_sum(int arr[], int n) {
    int best = 0;
    int current = 0;

    for (int i = 0; i < n; i++) {
        current += arr[i];
        if (current < 0) {
            current = 0;
        }
        if (current > best) {
            best = current;
        }
    }

    return best;
}

#include <algorithm>
#include <cstddef>
#include <vector>

int max_1d_range_sum(const std::vector<int>& values) {
    if (values.empty()) {
        return 0;
    }

    int best = values.front();
    int current = values.front();
    for (std::size_t index = 1; index < values.size(); ++index) {
        current = std::max(values[index], current + values[index]);
        best = std::max(best, current);
    }

    return std::max(0, best);
}

public class Max1DRangeSum {
	public static int max1dRangeSum(int[] array) {
		if (array == null || array.length == 0) {
			return 0;
		}
		int best = array[0];
		int current = array[0];
		for (int i = 1; i < array.length; i++) {
			current = Math.max(array[i], current + array[i]);
			best = Math.max(best, current);
		}
		return Math.max(0, best);
	}


	public static int getMax1DRangeSum(int n, int A[]){
		int current_sum = 0, ans = 0;
	    for (int i = 0; i < n; i++)
		 {
			if (current_sum + A[i] >= 0) {
			    current_sum += A[i];
			    ans = Math.max(ans, current_sum);
			  }
			else {
				current_sum = 0;
			}
	 	}
	    return ans;
	}

	public static void main(String[] args) {

		int n = 9, A[] = { 4, -5, 4, -3, 4, 4, -4, 4, -5 };
	    System.out.println(getMax1DRangeSum(n, A));         // should be 9
	}

}

fun max1dRangeSum(arr: IntArray): Int {
    var best = 0
    var current = 0

    for (value in arr) {
        current = maxOf(0, current + value)
        best = maxOf(best, current)
    }

    return best
}

func max1dRangeSum(_ arr: [Int]) -> Int {
    var best = 0
    var current = 0

    for value in arr {
        current = max(0, current + value)
        best = max(best, current)
    }

    return best
}
